    return sum + cursedSurcharge + enchantmentSurcharge;
  }, 0);

export const processScenario = (scenario: any): any => {
  const results: any[] = [];
  const policies: Record<number, { items: any[]; remainingCap: number }> = {};
  let quoteCount = 0;
  for (let i = 0; i < scenario.steps.length; i++) {
    const step = scenario.steps[i];
    if (step.op === "quote") {
      for (const item of step.items) {
        if (!isKnownItemType(item)) {
          throw new Error(`Unknown item type: ${item.type}`);
        }
      }
      const mainItems = step.items.filter((item: any) => !isComponent(item));
      const components = step.items.filter(isComponent);
      const basePremiumSum = calculateMainItemBaseTotal(mainItems) + calculateComponentTotal(components);
      const itemSurcharges = calculateItemLevelSurcharges(mainItems);
      const firstInsurance = basePremiumSum * FIRST_INSURANCE_RATE;
      const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremiumSum * LOYALTY_DISCOUNT_RATE : 0;
      const followUpDiscount = quoteCount > 0 ? basePremiumSum * FOLLOW_UP_DISCOUNT_RATE : 0;
      const premium = Math.ceil(basePremiumSum + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
      const insuranceSum = step.items.reduce((sum: number, item: any) => {
        return sum + (isComponent(item) ? COMPONENT_INSURANCE_VALUE : (INSURANCE_VALUES[item.type] ?? 0));
      }, 0);
      policies[i] = { items: step.items, remainingCap: insuranceSum * CAP_MULTIPLIER };
      results.push({ premium });
      quoteCount++;
    } else if (step.op === "claim") {
      const policy = policies[step.policy];
      let totalPayout = 0;
      for (const damage of step.incident.damages) {
        const payout = Math.max(0, damage.amount - DEDUCTIBLE);
        totalPayout += payout;
      }
      policy.remainingCap -= totalPayout;
      results.push({ payout: totalPayout, remainingCap: policy.remainingCap });
    }
  }
  return { results };
};

